/* INC_SS - arithmetic */
static void inst_INC_SS(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t ss = inst->ss & 0x03;
    if (ss == 0) {
    uint16_t bc = (uint16_t)((cpu->registers[REG_B] << 8) | cpu->registers[REG_C]);
    bc++;
    cpu->registers[REG_B] = (uint8_t)(bc >> 8);
    cpu->registers[REG_C] = (uint8_t)(bc & 0xFF);
    } else if (ss == 1) {
    uint16_t de = (uint16_t)((cpu->registers[REG_D] << 8) | cpu->registers[REG_E]);
    de++;
    cpu->registers[REG_D] = (uint8_t)(de >> 8);
    cpu->registers[REG_E] = (uint8_t)(de & 0xFF);
    } else if (ss == 2) {
    uint16_t hl = (uint16_t)((cpu->registers[REG_H] << 8) | cpu->registers[REG_L]);
    hl++;
    cpu->registers[REG_H] = (uint8_t)(hl >> 8);
    cpu->registers[REG_L] = (uint8_t)(hl & 0xFF);
    } else {
    cpu->sp++;
    }
}

/* DEC_SS - arithmetic */
static void inst_DEC_SS(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t ss = inst->ss & 0x03;
    if (ss == 0) {
    uint16_t bc = (uint16_t)((cpu->registers[REG_B] << 8) | cpu->registers[REG_C]);
    bc--;
    cpu->registers[REG_B] = (uint8_t)(bc >> 8);
    cpu->registers[REG_C] = (uint8_t)(bc & 0xFF);
    } else if (ss == 1) {
    uint16_t de = (uint16_t)((cpu->registers[REG_D] << 8) | cpu->registers[REG_E]);
    de--;
    cpu->registers[REG_D] = (uint8_t)(de >> 8);
    cpu->registers[REG_E] = (uint8_t)(de & 0xFF);
    } else if (ss == 2) {
    uint16_t hl = (uint16_t)((cpu->registers[REG_H] << 8) | cpu->registers[REG_L]);
    hl--;
    cpu->registers[REG_H] = (uint8_t)(hl >> 8);
    cpu->registers[REG_L] = (uint8_t)(hl & 0xFF);
    } else {
    cpu->sp--;
    }
}

